return items.map(item => {
  // Normaliza o nome removendo acentos e caracteres especiais
  const nameNormalized = item.json.name.normalize("NFD")
    .replace(/[\u0300-\u036f]/g, "") // Remove acentos
    .replace(/[\\[\\]()|]/g, "") // Remove caracteres especiais
    .replace(/[^a-zA-Z0-9]/g, "_") // Substitui caracteres não alfanuméricos por underscore
    .replaceAll("__", "")
    .trim(); // Remove duplicatas de underscores

  return {
    id: item.json.id,
    name: item.json.name,
    is_unavailable: item.json.is_unavailable,
    is_archived: item.json.is_archived,
    custom_event_type: item.json.custom_event_type,
    event_source_type: item.json.event_source_type,
    rule: item.json.rule,
    name_normalize: nameNormalized, // Usa o nome normalizado
    pixel_id: item.json.pixel?.id,
    default_conversion_value: item.json.default_conversion_value,
    retention_days: item.json.retention_days,
    data_source_id: item.json.data_sources?.[0]?.id,
    data_source_type: item.json.data_sources?.[0]?.source_type,
    data_source_name: item.json.data_sources?.[0]?.name
  };
});

